export class CargoPublisher {
    #workingDirectory;
    #execute;
    constructor(workingDirectory, execute) {
        this.#workingDirectory = workingDirectory;
        this.#execute = execute;
    }
    async dryRun(packages) {
        await this.#publish(packages, true);
    }
    async publish(packages) {
        await this.#publish(packages, false);
    }
    async #publish(packages, dryRun) {
        if (packages.length === 0) {
            throw new Error("Cargo publication requires at least one package");
        }
        const exitCode = await this.#execute("cargo", cargoPublishArguments(packages, dryRun), this.#workingDirectory);
        if (exitCode !== 0) {
            throw new Error(`cargo publish failed with exit code ${exitCode}`);
        }
    }
}
function cargoPublishArguments(packages, dryRun) {
    const arguments_ = ["publish", "--locked"];
    for (const item of packages) {
        arguments_.push("--package", item.name);
    }
    if (dryRun) {
        arguments_.push("--dry-run");
    }
    return arguments_;
}
